// Parsear el evento de Meta (Instagram DM o Facebook Messenger)
const body = $input.first().json.body;
const results = [];

if (!body || !body.entry) return [];

for (const entry of body.entry) {
  // Facebook Messenger
  if (entry.messaging) {
    for (const msg of entry.messaging) {
      if (!msg.message || msg.message.is_echo) continue;
      results.push({
        channel: 'facebook',
        sender_id: msg.sender.id,
        recipient_id: msg.recipient.id,
        message_id: msg.message.mid,
        text: msg.message.text || '[adjunto]',
        timestamp: new Date(msg.timestamp).toISOString(),
        page_id: entry.id,
      });
    }
  }
  // Instagram DM
  if (entry.changes) {
    for (const change of entry.changes) {
      if (change.field !== 'messages') continue;
      const val = change.value;
      if (!val.messages) continue;
      for (const msg of val.messages) {
        if (msg.from?.id === val.metadata?.phone_number_id) continue; // outbound
        results.push({
          channel: 'instagram',
          sender_id: msg.from?.id || val.sender?.id,
          recipient_id: val.recipient?.id,
          message_id: msg.id,
          text: msg.text?.body || msg.image ? '[imagen]' : '[adjunto]',
          timestamp: new Date(parseInt(msg.timestamp) * 1000).toISOString(),
          ig_account_id: val.metadata?.phone_number_id,
        });
      }
    }
  }
}

return results.map(r => ({ json: r }));

const parsed = $('Parsear evento Meta').first().json;
const existing = $input.all();

if (existing.length > 0 && existing[0].json.id) {
  return [{ json: { contact_id: existing[0].json.id, is_new: false, ...parsed } }];
} else {
  return [{ json: { contact_id: null, is_new: true, ...parsed } }];
}
